  innerFunction();
}

outerFunction();

function outerFunction() {
  var outerVar = 'I am outer!';

  function innerFunction() {
    console.log(outerVar); // 予想される出力: 'I am outer!'
  }

  return innerFunction;
}

var myFunction = outerFunction();
myFunction();

